#include <stdio.h>
#include <ctype.h>
#include <string.h>
int main() {
    char s[101];
    scanf("%s", s);
    int len = strlen(s);
    for (int i = 0; i < len; i++) {
        if (s[i] != 'a' && s[i] != 'e' && s[i] != 'i' && s[i] != 'o' && s[i] != 'u') {
            printf("%c", s[i]);
        }
    }
    return 0;
}

