code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
readline.on('line', (s) => {
    for (let c of s) {
        if ('aeiou'.indexOf(c) === -1) {
            process.stdout.write(c);
        }
    }
    readline.close();
});
